class Document:
    def __init__(self, title, content):
        self.title = title
        self.content = content
    def to_dict(self):
        return {'title': self.title, 'content': self.content}
    @classmethod
    def from_json(cls, data):
        return cls(title=data.get('title'), content=data.get('content'))

